"use client";

/**
 * BuilderBubble — a single message bubble for the Builder agent chat strip.
 *
 * PROMOTE is gated strictly to authorType === 'agent'. It will never render on
 * a user/human bubble. The button is intentionally subtle — the ceremony lives
 * in the promote modal (Step 6), not here.
 */

import { useState } from "react";
import type { ThreadMessage } from "@/types";

interface BuilderBubbleProps {
  message: ThreadMessage;
  onPromote: (message: ThreadMessage) => void;
  promoted?: boolean;
}

export function BuilderBubble({ message, onPromote, promoted = false }: BuilderBubbleProps) {
  const [hovered, setHovered] = useState(false);
  const isAgent = message.authorType === "agent";

  return (
    <div
      className={`group flex flex-col gap-1 ${isAgent ? "items-start" : "items-end"}`}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      {/* Role label */}
      <span className="text-[9px] font-bold tracking-[0.2em] uppercase text-[var(--muted)]/50 px-1">
        {isAgent ? (message.agentJobTitle || message.authorName || "Agent") : "You"}
      </span>

      {/* Bubble */}
      <div
        className={`relative max-w-full px-3 py-2.5 rounded-xl text-[12px] leading-relaxed whitespace-pre-wrap border transition-colors ${
          isAgent
            ? "bg-white/5 border-white/8 text-[var(--text-blue)] rounded-tl-none"
            : "bg-amber-500/8 border-amber-500/15 text-[var(--text-blue)]/90 rounded-tr-none"
        }`}
      >
        {message.text}

        {/* Action chips */}
        {message.actionsApplied && message.actionsApplied.length > 0 && (
          <div className="mt-1.5 flex flex-wrap gap-1">
            {message.actionsApplied.map((a, i) => (
              <span
                key={i}
                className="text-[9px] px-1.5 py-0.5 rounded-full bg-white/5 border border-white/10 text-[var(--muted)]"
              >
                {a}
              </span>
            ))}
          </div>
        )}
      </div>

      {/*
        PROMOTE button — agent bubbles only.
        Never rendered on role === 'user' bubbles.
        Subtle: sits quietly below the bubble, fades in on hover.
        Once promoted, shows a quiet QUEUED label instead.
      */}
      {isAgent && (
        <div className={`px-1 transition-opacity duration-150 ${hovered ? "opacity-100" : "opacity-0"}`}>
          {promoted ? (
            <span className="text-[9px] font-bold tracking-widest uppercase text-emerald-400/50">
              queued
            </span>
          ) : (
            <button
              type="button"
              onClick={() => onPromote(message)}
              className="text-[9px] font-bold tracking-widest uppercase text-[var(--muted)]/40 hover:text-amber-400/70 transition-colors"
            >
              promote
            </button>
          )}
        </div>
      )}
    </div>
  );
}
