"use client";

/**
 * BuilderAgentChat — the message history strip in the Builder right panel.
 * Sits above the agent input bar (AgentBar, Step 5b / future).
 * Passes onPromote up to BuilderShell, which owns the modal slot (Step 6).
 */

import { useEffect, useRef, useState } from "react";
import { useMessages } from "@/lib/hooks/useMessages";
import { BuilderBubble } from "./BuilderBubble";
import type { ThreadMessage } from "@/types";

interface BuilderAgentChatProps {
  projectId: string;
  runId: string;
  onPromote: (message: ThreadMessage) => void;
  /** Called before the first send of the session — prepends builder context to the message. */
  buildPreamble?: (openFilePath: string | null) => string;
}

export function BuilderAgentChat({ projectId, runId, onPromote, buildPreamble }: BuilderAgentChatProps) {
  const messages = useMessages(projectId, runId);
  const bottomRef = useRef<HTMLDivElement>(null);
  const [promotedIds, setPromotedIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  function handlePromote(message: ThreadMessage) {
    // Mark as promoted optimistically — modal (Step 6) confirms.
    setPromotedIds((prev) => new Set([...prev, message.id]));
    onPromote(message);
  }

  if (messages.length === 0) {
    return (
      <div className="flex-1 flex items-center justify-center min-h-0">
        <p className="text-[10px] text-[var(--muted)]/40 tracking-[0.2em] uppercase text-center px-4">
          Start a conversation
        </p>
      </div>
    );
  }

  return (
    <div className="flex-1 overflow-y-auto min-h-0 px-3 py-3 space-y-4 custom-scrollbar">
      {messages.map((m) => (
        <BuilderBubble
          key={m.id}
          message={m}
          onPromote={handlePromote}
          promoted={promotedIds.has(m.id)}
        />
      ))}
      <div ref={bottomRef} className="h-1" />
    </div>
  );
}
